-- Ken's Hardened V2 Fix

local b64_0xI1llII = {}
local char_0xlll1ll='ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/'
for i_0xIllIII=1,#char_0xlll1ll do b64_0xI1llII[char_0xlll1ll:sub(i_0xIllIII,i_0xIllIII)] = i_0xIllIII - 1 end

function b64_0xI1llII.dec_0xllIIl1(d_0xI1lI1I)
    d_0xI1lI1I = string.gsub(d_0xI1lI1I, '[^'..char_0xlll1ll..'=]', '')
    local r_0xlllI11 = {}
    for i_0xIllIII=1, #d_0xI1lI1I, 4 do
        local c_0xll1IIl = b64_0xI1llII[d_0xI1lI1I:sub(i_0xIllIII,i_0xIllIII)] or 0
        local c_0xl1lIII = b64_0xI1llII[d_0xI1lI1I:sub(i_0xIllIII+1,i_0xIllIII+1)] or 0
        local c_0x1llII1, c_0xIIll1I = 0, 0
        local has3 = true
        local has4 = true
        local ch3 = d_0xI1lI1I:sub(i_0xIllIII+2,i_0xIllIII+2)
        if ch3 == "=" then has3 = false else c_0x1llII1 = b64_0xI1llII[ch3] or 0 end
        local ch4 = d_0xI1lI1I:sub(i_0xIllIII+3,i_0xIllIII+3)
        if ch4 == "=" then has4 = false else c_0xIIll1I = b64_0xI1llII[ch4] or 0 end
        local b_0xllIl1I = c_0xll1IIl * (2^18) + c_0xl1lIII * (2^12) + c_0x1llII1 * (2^6) + c_0xIIll1I
        local b_0xl11IIl = math.floor(b_0xllIl1I / (2^16)) % (2^8)
        local b_0x1Illll = math.floor(b_0xllIl1I / (2^8)) % (2^8)
        local b_0xlI1I1l = b_0xllIl1I % (2^8)
        table.insert(r_0xlllI11, string.char(b_0xl11IIl))
        if has3 then table.insert(r_0xlllI11, string.char(b_0x1Illll)) end
        if has4 then table.insert(r_0xlllI11, string.char(b_0xlI1I1l)) end
    end
    return table.concat(r_0xlllI11)
end


local function bxor_0xII1Il1(a_0xlllI1l,b_0x1lI1ll)
    if bit32 then return bit32.bxor(a_0xlllI1l,b_0x1lI1ll) end
    local r_0xlIllll = 0
    for i_0xllIl11 = 0, 7 do
        local x_0x1I11I1 = a_0xlllI1l % 2
        local y_0xII1IlI = b_0x1lI1ll % 2
        if x_0x1I11I1 ~= y_0xII1IlI then r_0xlIllll = r_0xlIllll + (2^i_0xllIl11) end
        a_0xlllI1l = math.floor(a_0xlllI1l / 2)
        b_0x1lI1ll = math.floor(b_0x1lI1ll / 2)
    end
    return r_0xlIllll
end


local function bxor_str_0xllllIl(s_0x11llIl, k_0xlllll1)
    local r_0xIlIlll = {}
    for i_0xlI1Ill=1, #s_0x11llIl do
        local b_0xIl1lIl = string.byte(s_0x11llIl, i_0xlI1Ill)
        local kb_0xIllI1I = string.byte(k_0xlllll1, (i_0xlI1Ill-1) % #k_0xlllll1 + 1)
        r_0xIlIlll[i_0xlI1Ill] = string.char(bxor_0xII1Il1(b_0xIl1lIl, kb_0xIllI1I))
    end
    return table.concat(r_0xIlIlll)
end


local function getkeys_0xIlIl1I()
    local seed = b64_0xI1llII.dec_0xllIIl1("eTRMak5aNEE=")
    local k1_enc = b64_0xI1llII.dec_0xllIIl1("NU0dJC82cDc=")
    local k2_enc = b64_0xI1llII.dec_0xllIIl1("I2F5Mz0WZjs=")
    return bxor_str_0xllllIl(k1_enc, seed), bxor_str_0xllllIl(k2_enc, seed)
end


local function cff_0xllIIIl(a_0xI1llll)
    local st_0xIIl1lI = 0
    local res_0x11IIlI = a_0xI1llll
    while true do
        if st_0xIIl1lI == 0 then
            res_0x11IIlI = res_0x11IIlI + 1
            st_0xIIl1lI = 1
        elseif st_0xIIl1lI == 1 then
            res_0x11IIlI = res_0x11IIlI * 2
            st_0xIIl1lI = 2
        elseif st_0xIIl1lI == 2 then
            res_0x11IIlI = res_0x11IIlI - 3
            st_0xIIl1lI = 3
        else
            break
        end
    end
    return res_0x11IIlI
end


local function chain_0xIIIII1(x) return x*2 end
local function chain_0x1lIl1I(x) return chain_0xIIIII1(x)+1 end


local d_0xIllII1 = {
  {op=255, val="", is_enc=true},
}
local pc_0x1lI1II = 1
local stk_0xI1II1l = {}
stk_0xI1II1l._jmp = nil


local disp_0xIlIlII = {
    [0] = function() end,
    [1] = function(s, v) table.insert(s, v) end,
    [2] = function(s, v) table.insert(s, _G[v]) end,
    [3] = function(s, v) local val=table.remove(s); _G[v]=val end,
    [4] = function(s, _) table.insert(s, {}) end,
    [5] = function(s, _) local val=table.remove(s); local key=table.remove(s); local t=table.remove(s); t[key]=val; table.insert(s, t) end,
    [16] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a+b) end,
    [17] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a-b) end,
    [18] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a*b) end,
    [19] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a/b) end,
    [32] = function(s, n) 
        local args = {}
        for i=1,tonumber(n) do table.insert(args, 1, table.remove(s)) end
        local f = table.remove(s)
        if type(f) == "function" then
            local result = {f(unpack(args))}
            for _,v in ipairs(result) do table.insert(s, v) end
        else
            print("[LBI] Not a function: "..tostring(f))
        end
    end,
    [33] = function(s) return table.remove(s) end,
    [48] = function(s, offset) 
        local cond = table.remove(s)
        if not cond then 
            s._jmp = tonumber(offset)
        end
    end,
    [49] = function(s, offset)
        s._jmp = tonumber(offset)
    end,
    [255] = function(s, v)
        local fn, err = loadstring(v)
        if not fn then
            print("[LBI] Load error: "..tostring(err))
        else
            local ok, res = pcall(fn)
            if not ok then print("[LBI] Run error: "..tostring(res)) end
        end
    end
}



local k1, k2 = getkeys_0xIlIl1I()

local state_0xII1IlI = 0
while true do
    if state_0xII1IlI == 0 then  -- FETCH
        if pc_0x1lI1II > #d_0xIllII1 then break end
        local inst = d_0xIllII1[pc_0x1lI1II]
        local opcode = inst.op
        local val = inst.val
        if inst.is_enc then
            local d = b64_0xI1llII.dec_0xllIIl1(val)
            d = bxor_str_0xllllIl(d, k2)
            val = bxor_str_0xllllIl(d, k1)
        end
        stk_0xI1II1l._jmp = nil
        pc_0x1lI1II = pc_0x1lI1II + 1
        cur_op_0xIl11Il = opcode
        cur_val_0xIlIllI = val
        state_0xII1IlI = 1

    elseif state_0xII1IlI == 1 then  -- EXECUTE
        local handler = disp_0xIlIlII[cur_op_0xIl11Il]
        if handler then
            handler(stk_0xI1II1l, cur_val_0xIlIllI)
        end
        if stk_0xI1II1l._jmp then
            pc_0x1lI1II = pc_0x1lI1II + stk_0xI1II1l._jmp
        end
        state_0xII1IlI = 0
    else
